1	import { NextResponse } from "next/server";
2	import { getFounderFromAuth } from "@/lib/apiKeyAuth";
3	import { db } from "@/lib/db";
4	import { enqueueIngestJob } from "@/lib/jobQueue";
5	import { extractText } from "@/lib/extractText";
6	import { sanitizeText, sanitizeAndCap } from "@/lib/sanitizeText";
7	import { pickAvailableSlug } from "@/lib/slugify";
8	import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
9	import {
10	  isAudioStorageConfigured,
11	  uploadAudioBuffer,
12	} from "@/lib/supabaseStorage";
13	import { triggerNoosphereProcessing } from "@/lib/triggerNoosphereProcessing";
14	import { writeFile, mkdir } from "fs/promises";
15	import { join, extname } from "path";
16	import { v4 as uuid } from "uuid";
17	
18	/**
19	 * Multipart upload handler.
20	 *
21	 * On Vercel (serverless) we can't rely on the filesystem — any writes to
22	 * `process.cwd()/uploads` disappear the instant the request returns.
23	 * Instead, this route extracts whatever textual content it can from the
24	 * uploaded file (plain text, PDF body, DOCX paragraphs, Whisper
25	 * transcript of audio) and persists it directly into `Upload.textContent`.
26	 * That makes the row immediately usable by `noosphere ingest-from-codex`
27	 * — no file retrieval needed.
28	 *
29	 * Supported types out of the box (all extracted → textContent):
30	 *   .txt .md .markdown .vtt .jsonl   (UTF-8 pass-through)
31	 *   .pdf                              (via pdf-parse)
32	 *   .docx                             (via mammoth)
33	 *   .mp3 .m4a .wav .webm .ogg         (via OpenAI Whisper; needs API key)
34	 *
35	 * For self-hosted deploys (UPLOAD_STORAGE unset), we also write the
36	 * original binary to `UPLOAD_LOCAL_DIR` so the Noosphere CLI running
37	 * locally can fall back to the raw file if extraction produced nothing.
38	 */
39	
40	const UPLOAD_DIR =
41	  process.env.UPLOAD_LOCAL_DIR || join(process.cwd(), "uploads");
42	const DISABLE_LOCAL_WRITES =
43	  process.env.VERCEL === "1" || process.env.UPLOAD_STORAGE === "remote";
44	
45	// Vercel Hobby: 4.5 MB request body cap. We leave 100 KB headroom for
46	// form fields (title, description, etc.) so the raw file can be
47	// ~4.4 MB. Self-hosted deploys aren't subject to this — `writeFile`
48	// can handle arbitrary sizes — but enforcing it everywhere keeps the
49	// server-vs-serverless behaviour predictable and makes local testing
50	// catch the eventual Vercel failure earlier.
51	const MAX_FILE_BYTES = Math.floor(4.4 * 1024 * 1024);
52	
53	const ALLOWED_EXT = new Set([
54	  ".md",
55	  ".markdown",
56	  ".txt",
57	  ".vtt",
58	  ".jsonl",
59	  // Dialectic posts its per-session reflection bundle as a single JSON blob
60	  // (`{session_id}_reflection.json`). Accept it so the interlocutor record
61	  // round-trips into the Codex without extra rewriting on the desktop side.
62	  ".json",
63	  ".pdf",
64	  ".docx",
65	  ".mp3",
66	  ".m4a",
67	  ".wav",
68	  ".webm",
69	  ".ogg",
70	]);
71	
72	export async function POST(req: Request) {
73	  try {
74	    // Accept either a browser cookie session or a `Authorization: Bearer tcx_…`
75	    // API key so Dialectic (and any CLI/automation) can upload without a UI.
76	    const founder = await getFounderFromAuth(req);
77	    if (!founder) {
78	      return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
79	    }
80	    // Role gate: viewers can read every artifact in their org but cannot
81	    // upload new material. The check happens AFTER auth (so an
82	    // unauthenticated caller still sees 401, not 403) and BEFORE any
83	    // file parsing, so a giant payload doesn't get streamed in for a
84	    // request we'll reject anyway.
85	    if (!canWrite(founder.role)) {
86	      return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
87	    }
88	
89	    const formData = await req.formData();
90	    const file = formData.get("file") as File | null;
91	    const title = (formData.get("title") as string) || "";
92	    const description = (formData.get("description") as string) || "";
93	    const sourceType = (formData.get("sourceType") as string) || "written";
94	    // Blog publish fields — default OFF. Accept "1"/"true"/"on"/"yes"
95	    // to handle different front-end conventions; everything else
96	    // including the empty string keeps the upload unpublished.
97	    const rawPublish = (formData.get("publishAsPost") as string) || "";
98	    const publishAsPost = ["1", "true", "on", "yes"].includes(
99	      rawPublish.toLowerCase(),
100	    );
101	    const blogExcerptInput = (formData.get("blogExcerpt") as string) || "";
102	    const authorBioInput = (formData.get("authorBio") as string) || "";
103	    // Visibility ladder — three levels; see Upload.visibility in
104	    // schema.prisma. Anything not in the allow-list falls through to
105	    // the default "org" (firm-shared, publishable).
106	    const rawVisibility = (
107	      (formData.get("visibility") as string) || "org"
108	    ).toLowerCase();
109	    const visibility: "org" | "semi-private" | "private" =
110	      rawVisibility === "private"
111	        ? "private"
112	        : rawVisibility === "semi-private"
113	          ? "semi-private"
114	          : "org";
115	    // Blog-publishing is only allowed for "org" uploads. Private =
116	    // nobody else sees it → publishing is nonsense. Semi-private =
117	    // firm-only by construction → publishing is a hard violation of
118	    // the level's promise. Fail fast with a clear message before we
119	    // do the expensive extraction + write.
120	    if (visibility !== "org" && publishAsPost) {
121	      return NextResponse.json(
122	        {
123	          error:
124	            visibility === "private"
125	              ? "An upload can't be both private and published as a blog post. Choose one."
126	              : "An upload can't be both semi-private and published as a blog post. Choose one.",
127	        },
128	        { status: 400 },
129	      );
130	    }
131	
132	    if (!file) {
133	      return NextResponse.json({ error: "No file provided" }, { status: 400 });
134	    }
135	
136	    const ext = extname(file.name).toLowerCase();
137	    if (!ALLOWED_EXT.has(ext)) {
138	      return NextResponse.json(
139	        {
140	          error:
141	            `Unsupported file type ${ext || "(none)"}. Allowed: ` +
142	            [...ALLOWED_EXT].join(", "),
143	        },
144	        { status: 400 },
145	      );
146	    }
147	
148	    const buffer = Buffer.from(await file.arrayBuffer());
149	    if (buffer.length > MAX_FILE_BYTES) {
150	      return NextResponse.json(
151	        {
152	          error:
153	            `File is ${(buffer.length / 1024 / 1024).toFixed(1)} MB; the serverless ` +
154	            `upload limit is ${(MAX_FILE_BYTES / 1024 / 1024).toFixed(1)} MB. ` +
155	            "For larger files, upload from a local Noosphere CLI — or wait for " +
156	            "the Supabase Storage direct-upload flow.",
157	        },
158	        { status: 413 },
159	      );
160	    }
161	
162	    const mime = file.type || "";
163	
164	    // ── Extract text/transcript from the file ───────────────────────────
165	    // This happens BEFORE the Upload row is created, so `textContent` is
166	    // populated on insert and Noosphere can process the row immediately.
167	    // `extractText` never throws — it returns a structured result with
168	    // `textContent` (possibly null), a `note`, and a `hardFailed` flag.
169	    const extraction = await extractText(buffer, file.name, mime);
170	
171	    // ── Upload audio to Supabase Storage (if configured + small) ────────
172	    // Only this server-side path handles audio that fits under Vercel's
173	    // 4.4 MB body cap. Big podcast files MUST use the signed-URL flow
174	    // at /api/upload/audio/prepare → direct PUT → /api/upload/audio/finalize
175	    // (those bypass Vercel entirely). We still persist the audio for
176	    // small files here so the upload form stays a one-step flow for
177	    // short clips.
178	    const isAudio =
179	      mime.startsWith("audio/") ||
180	      /\.(mp3|m4a|wav|webm|ogg)$/i.test(file.name);
181	    let audioUrl: string | null = null;
182	    if (isAudio && isAudioStorageConfigured()) {
183	      try {
184	        // Object path: <upload-id>/<original filename>. We don't have
185	        // the upload id yet (created below), so we generate a
186	        // placeholder uuid prefix and pass it into the upload create
187	        // step. This keeps the object path deterministic enough to
188	        // find later via listbucket prefix queries.
189	        const objectPath = `${uuid()}/${file.name.replace(/[^A-Za-z0-9._-]+/g, "_")}`;
190	        audioUrl = await uploadAudioBuffer(
191	          objectPath,
192	          new Uint8Array(buffer),
193	          mime || "audio/mpeg",
194	        );
195	      } catch (err) {
196	        // Non-fatal — the upload itself still succeeds; the blog post
197	        // just won't have a player. Log the reason into processLog so
198	        // the user can diagnose.
199	        console.error("Supabase audio upload failed:", err);
200	      }
201	    }
202	
203	    // ── Persist raw bytes (self-hosted only) ────────────────────────────
204	    // On Vercel we lose the binary the moment the request returns, so we
205	    // deliberately don't write it; `filePath` is a synthetic `inline:` id.
206	    let filePath: string;
207	    if (!DISABLE_LOCAL_WRITES) {
208	      await mkdir(UPLOAD_DIR, { recursive: true });
209	      const storedName = `${uuid()}${ext || ".bin"}`;
210	      filePath = join(UPLOAD_DIR, storedName);
211	      await writeFile(filePath, buffer);
212	    } else {
213	      filePath = `inline:${uuid()}${ext}`;
214	    }
215	
216	    // ── Create the Upload row ───────────────────────────────────────────
217	    // Every string headed for Postgres is sanitized here for two
218	    // reasons:
219	    //   1. Postgres rejects UTF-8 NUL bytes ("invalid byte sequence
220	    //      for encoding "UTF8": 0x00") — PDFs and DOCX extraction
221	    //      leak these. `extractText` already strips them, but we
222	    //      scrub again on the boundary so a future caller that
223	    //      bypasses `extractText` (e.g. a direct API client) can't
224	    //      poison the DB.
225	    //   2. Titles/descriptions/filenames are user-controlled, so
226	    //      strip C0 control chars that have no business in a label.
227	    const safeTitle = sanitizeText(
228	      title || file.name.replace(/\.[^/.]+$/, ""),
229	    ).slice(0, 500);
230	    const safeDescription = sanitizeAndCap(description, 10_000);
231	    const safeOriginalName = sanitizeText(file.name).slice(0, 500);
232	    const safeMime = sanitizeText(mime || "application/octet-stream").slice(0, 255);
233	    const initialLog = sanitizeAndCap(
234	      `— Upload received (${buffer.length.toLocaleString()} bytes) —\n` +
235	        `— Extraction: ${extraction.note} —\n`,
236	      8_000,
237	    );
238	
239	    // If the founder asked to publish this upload as a blog post,
240	    // mint a URL-safe slug from the title and grab the optional
241	    // excerpt/byline overrides. Slug uniqueness is enforced in the
242	    // DB (Upload_slug_key) — `pickAvailableSlug` probes until it
243	    // finds an unused one, falling back to a hex suffix if a hundred
244	    // numeric attempts all collide.
245	    let publishFields: {
246	      publishedAt: Date;
247	      slug: string;
248	      blogExcerpt: string | null;
249	      authorBio: string | null;
250	    } | null = null;
251	    if (publishAsPost) {
252	      const slug = await pickAvailableSlug(safeTitle, async (candidate) => {
253	        const existing = await db.upload.findUnique({
254	          where: { slug: candidate },
255	          select: { id: true },
256	        });
257	        return existing !== null;
258	      });
259	      publishFields = {
260	        publishedAt: new Date(),
261	        slug,
262	        blogExcerpt: blogExcerptInput
263	          ? sanitizeAndCap(blogExcerptInput, 400)
264	          : null,
265	        authorBio: authorBioInput
266	          ? sanitizeAndCap(authorBioInput, 160)
267	          : null,
268	      };
269	    }
270	
271	    const upload = await db.upload.create({
272	      data: {
273	        organizationId: founder.organizationId,
274	        founderId: founder.id,
275	        title: safeTitle,
276	        description: safeDescription,
277	        sourceType: sanitizeText(sourceType).slice(0, 64) || "written",
278	        originalName: safeOriginalName,
279	        mimeType: safeMime,
280	        filePath,
281	        fileSize: buffer.length,
282	        textContent: extraction.textContent,
283	        status: "pending",
284	        processLog: initialLog,
285	        errorMessage: extraction.hardFailed
286	          ? sanitizeAndCap(extraction.note, 2_000)
287	          : null,
288	        visibility,
289	        audioUrl,
290	        ...(publishFields ?? {}),
291	      },
292	    });
293	
294	    await db.auditEvent.create({
295	      data: {
296	        organizationId: founder.organizationId,
297	        founderId: founder.id,
298	        uploadId: upload.id,
299	        action: "upload",
300	        detail: sanitizeAndCap(
301	          `Uploaded ${file.name} (${(buffer.length / 1024).toFixed(0)} KB) · ${extraction.mode}`,
302	          2_000,
303	        ),
304	      },
305	    });
306	
307	    // Serialize the two async side-effects to avoid a race that was
308	    // clobbering the dispatch note. Order:
309	    //   1. Fire the GitHub Actions dispatch (fast, ~200ms HTTP POST).
310	    //   2. Wait for the response, append its status to processLog.
311	    //   3. THEN kick off `enqueueIngestJob` (slow on Vercel — does
312	    //      extraction fallback + appends its own notes).
313	    // Because step 3 reads-then-writes via `appendLog`, previous notes
314	    // are preserved. Previously both steps raced to overwrite the
315	    // field and the dispatch note was usually lost.
316	    const dispatchPromise = (async () => {
317	      try {
318	        const result = await triggerNoosphereProcessing(upload.id, {
319	          organizationId: founder.organizationId,
320	          withLlm: true,
321	        });
322	        const suffix = `\n— Auto-process: ${result.note} —\n`;
323	        try {
324	          await db.upload.update({
325	            where: { id: upload.id },
326	            data: {
327	              // Append the dispatch note to the existing processLog so
328	              // a later ingest-job write doesn't wipe it. (jobQueue's
329	              // `appendLog` is also read-then-write so subsequent lines
330	              // will preserve this too.)
331	              processLog: {
332	                set: sanitizeAndCap(initialLog + suffix, 8_000),
333	              },
334	              status: result.dispatched ? "processing" : upload.status,
335	            },
336	          });
337	        } catch {
338	          /* non-fatal */
339	        }
340	      } finally {
341	        // Always run the fallback ingest job. On Vercel it detects the
342	        // lack of Python and, if auto-processing is configured, writes
343	        // a short "handed off to GitHub Actions" note; if not, it
344	        // writes the full "run locally" instructions. Either way it
345	        // appends to the existing processLog instead of overwriting.
346	        try {
347	          await enqueueIngestJob(upload.id);
348	        } catch (err) {
349	          console.error(
350	            `Background ingestion for upload ${upload.id} failed:`,
351	            err,
352	          );
353	        }
354	      }
355	    })();
356	    // Non-blocking from the HTTP response's perspective — the user gets
357	    // their upload ack immediately. The dispatch + jobQueue work
358	    // continues after response close on Vercel's serverless runtime.
359	    void dispatchPromise;
360	
361	    return NextResponse.json({
362	      id: upload.id,
363	      status: upload.status,
364	      title: upload.title,
365	      fileSize: upload.fileSize,
366	      extractionMode: extraction.mode,
367	      textContentChars: extraction.textContent?.length ?? 0,
368	      note: extraction.note,
369	      autoProcessing: true,
370	      // Publish surface: empty when the upload stayed private, or the
371	      // live URL when it was published. Clients (the React form) show
372	      // this as a toast after a successful post so the author can
373	      // share / verify immediately.
374	      publishedAt: upload.publishedAt,
375	      slug: upload.slug,
376	      publicUrl: upload.slug ? `/post/${upload.slug}` : null,
377	      visibility: upload.visibility,
378	      isPrivate: upload.visibility === "private",
379	    });
380	  } catch (error) {
381	    console.error("Upload error:", error);
382	    return NextResponse.json(
383	      {
384	        error:
385	          `Upload failed: ${error instanceof Error ? error.message : "unknown error"}`,
386	      },
387	      { status: 500 },
388	    );
389	  }
390	}
