1	/**
2	 * POST /api/upload/:id/delete — OWNER-ONLY direct deletion.
3	 *
4	 * The only path to soft-delete an upload without going through a
5	 * DeletionRequest. Rules:
6	 *
7	 *   * Caller must be authenticated.
8	 *   * Caller must belong to the upload's organization.
9	 *   * Caller must be the upload's `founderId`. If not, the request
10	 *     returns 403 with instructions pointing at the peer request API.
11	 *
12	 * On success:
13	 *   * `Upload.deletedAt = now()`.
14	 *   * `Upload.publishedAt = null` (so the row can't stay on the blog
15	 *     while hidden from the library — keeps the two surfaces in sync).
16	 *   * Any pending `DeletionRequest` rows for this upload are moved to
17	 *     `status='cancelled'` with a decision note so requesters aren't
18	 *     left waiting on a response that will never come.
19	 *   * An `AuditEvent` records the deletion.
20	 */
21	import { NextResponse } from "next/server";
22	import { getFounderFromAuth } from "@/lib/apiKeyAuth";
23	import { db } from "@/lib/db";
24	import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
25	import { sanitizeAndCap } from "@/lib/sanitizeText";
26	import {
27	  cascadeDeleteUploadArtifacts,
28	  formatCascadeCounts,
29	} from "@/lib/uploadDeleteCascade";
30	
31	export async function POST(
32	  req: Request,
33	  { params }: { params: Promise<{ id: string }> },
34	) {
35	  try {
36	    const founder = await getFounderFromAuth(req);
37	    if (!founder) {
38	      return NextResponse.json(
39	        { error: "Not authenticated" },
40	        { status: 401 },
41	      );
42	    }
43	    // Viewers can read but not delete — even their own uploads (if
44	    // any survive from before they were demoted to viewer, an admin
