/**
 * GET /api/library — org-wide upload inventory.
 *
 * Every founder in the org can see every upload (public transparency
 * into the firm's collective input). Per-row ownership + request state
 * is included so the UI can decide whether to render "Delete" (owner)
 * vs. "Request deletion" (non-owner).
 *
 * Filters supported via query params:
 *   ?q=           free-text match on title / originalName (case-insensitive)
 *   ?author=      restrict to uploads by a specific founderId
 *   ?published=1  only published posts
 *   ?status=      upload status ("pending" | "processing" | "queued_offline"
 *                 | "ingested" | "failed")
 *
 * Deleted rows never appear here — the whole point of soft-delete is
 * that they're invisible on every surface.
 */
import { NextResponse } from "next/server";
import { getFounderFromAuth } from "@/lib/apiKeyAuth";
import { db } from "@/lib/db";

export async function GET(req: Request) {
  const founder = await getFounderFromAuth(req);
  if (!founder) {
    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
  }

  const url = new URL(req.url);
  const q = (url.searchParams.get("q") || "").trim();
  const author = (url.searchParams.get("author") || "").trim();
  const published = url.searchParams.get("published");
  const status = (url.searchParams.get("status") || "").trim();

  // Visibility rule: you can see any row that is either not private
  // or that you own. Encoded as an `OR` in the `AND` — `where.AND`
  // composes with the rest so simple filter queries (status, author)
  // compose cleanly.
  const baseAnd: Array<Record<string, unknown>> = [
    {
      OR: [
        { visibility: { not: "private" } },
        { founderId: founder.id },
      ],
    },
  ];
  const where: Record<string, unknown> = {
    organizationId: founder.organizationId,
    deletedAt: null,
    AND: baseAnd,
  };
  if (author) where.founderId = author;
  if (status) where.status = status;
  if (published === "1") where.publishedAt = { not: null };
  if (q) {
    baseAnd.push({
      OR: [
        { title: { contains: q, mode: "insensitive" } },
        { originalName: { contains: q, mode: "insensitive" } },
        { description: { contains: q, mode: "insensitive" } },
      ],
    });
  }

  const uploads = await db.upload.findMany({
    where,
    orderBy: { createdAt: "desc" },
    take: 250, // library is a browsing surface — 250 rows is plenty
    select: {
      id: true,
      title: true,
      originalName: true,
      sourceType: true,
      mimeType: true,
      fileSize: true,
      status: true,
      publishedAt: true,
      slug: true,
      visibility: true,
      createdAt: true,
      founderId: true,
      founder: { select: { id: true, name: true } },
      deletionRequests: {
        where: { status: "pending" },
        select: {
          id: true,
          status: true,
          reason: true,
          createdAt: true,
          requesterId: true,
          requester: { select: { id: true, name: true } },
        },
      },
    },
  });

  // Convenience: annotate each row with `youOwn` + whether `you`ve
  // already raised a request on this upload (avoid UI double-dispatch).
  const rows = uploads.map((u) => ({
    ...u,
    youOwn: u.founderId === founder.id,
    yourPendingRequestId:
      u.deletionRequests.find((r) => r.requesterId === founder.id)?.id || null,
  }));

  return NextResponse.json({
    you: { id: founder.id, name: founder.name },
    count: rows.length,
    rows,
  });
}

import { NextResponse } from "next/server";
import { getFounder } from "@/lib/auth";
import { db } from "@/lib/db";

/**
 * GET /api/upload/:id — poll status and streamed process log.
 */
export async function GET(_req: Request, { params }: { params: Promise<{ id: string }> }) {
  const founder = await getFounder();
  if (!founder) {
    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
  }

  const { id } = await params;

  const upload = await db.upload.findFirst({
    // `deletedAt: null` hides soft-deleted rows from the polling UI —
    // the row still exists in the DB (for audit) but is no longer
    // surfaced to any founder or the public blog.
    //
    // Private rows are also filtered so a peer can't hit this endpoint
    // with a guessed id and read the content. The owner still sees
    // their own private rows (the `OR` clause below).
    where: {
      id,
      organizationId: founder.organizationId,
      deletedAt: null,
      OR: [
        { visibility: { not: "private" } },
        { founderId: founder.id },
      ],
    },
    select: {
      id: true,
      founderId: true,
      organizationId: true,
      title: true,
      status: true,
      processLog: true,
      claimsCount: true,
      methodCount: true,
      substCount: true,
      principleCount: true,
      errorMessage: true,
      slug: true,
      publishedAt: true,
      createdAt: true,
      updatedAt: true,
    },
  });

  if (!upload) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  const sameOrg = upload.organizationId === founder.organizationId;
  if (!sameOrg) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }
  if (upload.founderId !== founder.id && founder.role !== "admin") {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  // Derive a publicUrl when the upload has been published. The slug is
  // stable (we never rewrite it once assigned), so the public URL can
  // be constructed deterministically without another DB lookup. The
  // client uses this to render a "view post" link on successfully
  // ingested rows in the upload queue.
  const publicUrl =
    upload.publishedAt && upload.slug ? `/post/${upload.slug}` : null;

  return NextResponse.json({ ...upload, publicUrl });
}

